/**
 * Shared matching engine for FilterField suggestions.
 *
 * Two questions are asked of every suggestion against the current search term:
 *  1. Does it match? (used for filtering — see `suggestionMatchesTerm`)
 *  2. How well does it match? (used for sorting — see `getSuggestionMatchPriority`)
 *
 * Both questions are answered against the same set of "match targets" (see
 * `getSuggestionMatchTargets`) and the same text normalization
 * (see `normalizeSuggestionMatchText`) so filtering and sorting can never drift apart.
 */

import type { FilterFieldSuggestion } from '../../suggestions/Suggestion.types.js';

export type SuggestionMatchingOptions = {
  /**
   * When `false`, the suggestion's `details` text is excluded from matching.
   * Used at call sites that match suggestions which carry display-only details
   * (e.g. logical-operator suggestions).
   * @defaultValue true
   */
  includeDetails?: boolean;
};

/**
 * Canonicalizes text for matching: strips quotes/backslashes and lowercases.
 * Applied to both the search term and every match target so quoted/escaped
 * user input compares against the same normalized form as raw suggestion text.
 * @internal
 */
export function normalizeSuggestionMatchText(value: string) {
  return value.replace(/(["'\\])/g, '').toLowerCase();
}

/**
 * Returns the normalized strings of a suggestion that participate in matching.
 *
 * Rules:
 *  - `displayValue` and `value` are mutually exclusive: if a string `displayValue`
 *    is provided, it wins (that's what the user sees and types against);
 *    otherwise the raw `value` is used.
 *  - `details` is an *additional* target, only when it's a string and details
 *    matching is enabled via options.
 *
 * Non-string fields (ReactNode `displayValue`/`details`, array `value`, etc.)
 * are silently skipped — they can't be substring-matched against a typed term.
 *
 * Kept private: only the two primitives below (`suggestionMatchesTerm`,
 * `getSuggestionMatchPriority`) need to know how targets are derived.
 */
function getSuggestionMatchTargets(
  suggestion: FilterFieldSuggestion,
  options: SuggestionMatchingOptions = {},
): string[] {
  const { includeDetails = true } = options;
  const targets: string[] = [];

  if (typeof suggestion.displayValue === 'string') {
    targets.push(suggestion.displayValue);
  } else if (typeof suggestion.value === 'string') {
    targets.push(suggestion.value);
  }

  if (includeDetails && typeof suggestion.details === 'string') {
    targets.push(suggestion.details);
  }

  return targets.map(normalizeSuggestionMatchText);
}

/**
 * Filtering primitive: does any match target contain the normalized term?
 * @internal
 */
export function suggestionMatchesTerm(
  suggestion: FilterFieldSuggestion,
  term: string,
  options?: SuggestionMatchingOptions,
): boolean {
  const normalizedTerm = normalizeSuggestionMatchText(term);

  return getSuggestionMatchTargets(suggestion, options).some((target) =>
    target.includes(normalizedTerm),
  );
}

/**
 * Position score for a single target against the needle.
 * Lower is better — used by sort comparators that want exact > startsWith > contains.
 */
function getMatchPriority(normalizedValue: string, needle: string): number {
  if (normalizedValue === needle) {
    return 0; // exact match
  }
  if (normalizedValue.startsWith(needle)) {
    return 1; // prefix match
  }

  return 2; // contains (or no match — same bucket; non-matches are pre-filtered)
}

/**
 * Sorting primitive: best (lowest) priority across all of the suggestion's
 * match targets. A suggestion that matches by `value` exactly is ranked above
 * one that only contains the term in `details`, etc.
 *
 * Returns 2 (worst bucket) when no targets exist, so suggestions without
 * matchable text sort to the end without throwing.
 * @internal
 */
export function getSuggestionMatchPriority(
  suggestion: FilterFieldSuggestion,
  normalizedTerm: string,
  options?: SuggestionMatchingOptions,
): number {
  const targets = getSuggestionMatchTargets(suggestion, options);

  if (targets.length === 0) {
    return 2;
  }

  return Math.min(
    ...targets.map((target) => getMatchPriority(target, normalizedTerm)),
  );
}
